parameters.text:
=Topic: {{ $json.output.topic }}
Target Audience: {{ $json.output.target_audience }}
Content Bucket: {{ $json.output.content_bucket }}
Category: {{ $json.output.category }}

Ideas: {{ $json.output.ideas }}

Select only the top 3 ideas with highest engagement potential.
Return only JSON:
{
  "category": "{{ $json.output.category }}",
  "top_3_ideas": ["idea1", "idea2", "idea3"],
  "topic": "{{ $json.output.topic }}",
  "content_bucket": "{{ $json.output.content_bucket }}",
  "target_audience": "{{ $json.output.target_audience }}"
}

parameters.jsCode:
// Prepare 3 rows, one for each idea
const rows = ($json.output.ideas || []).map(idea => ({
  Category: $json.output.category || "",
  Content_Bucket: $json.output.content_bucket || "",
  Target_Audience: $json.output.target_audience || "",
  Idea: idea || ""
}));

// Step 1: Stringify
const jsonString = JSON.stringify(rows);

// Step 2: URL encode for Zoho Sheets
const encoded = encodeURIComponent(jsonString);

return {
  json: {
    json_data: encoded
  }
};

// Handle the JSON whether it's array or object
let input = $json;

// If the input is an array, use the first element
if (Array.isArray(input)) {
  input = input[0];
}

// Safety check
if (!input || !input.records || !Array.isArray(input.records)) {
  return [];
}

const items = [];

for (const r of input.records) {
  if (String(r.Approval).toLowerCase() === "yes") {

    // Split target audience into clean array
    const targetAudienceArray = r.Target_Audience
      ? r.Target_Audience.split(",").map(a => a.trim())
      : [];

    // Build tags
    const tags = [
      ...(r.Category ? [r.Category] : []),
      ...(r.Content_Bucket ? [r.Content_Bucket] : []),
      ...targetAudienceArray
    ];

    items.push({
      json: {
        idea: r.Idea,
        category: r.Category || null,
        content_bucket: r.Content_Bucket || null,
        target_audience: targetAudienceArray,
        tags: tags
      }
    });
  }
}

return items;

